const express = require('express');
const mongoose = require('mongoose');
const Schema = mongoose.Schema;

// Define a User schema
const userSchema = new Schema({
  name: String,
  age: Number,
  password: String
});

// Connect to MongoDB and define the User model
mongoose.connect('mongodb://localhost/test', { useNewUrlParser: true, useUnifiedTopology: true })
  .then(() => console.log('Connected to MongoDB'))
  .catch(err => console.error('Could not connect to MongoDB:', err));

const User = mongoose.model('User', userSchema);

// Query builder function
function queryBuilder(filter, projection, sort) {
  const query = {};
  if (Object.keys(filter).length > 0) {
    Object.keys(filter).forEach(key => {
      if (filter[key] && filter[key].$where) {
        query[key] = eval(filter[key].$where);
      } else if (filter[key]) {
        query[key] = filter[key];
      }
    });
  }

  const projectionQuery = {};
  if (Object.keys(projection).length > 0) {
    Object.keys(projection).forEach(key => {
      if (projection[key]) {
        projectionQuery[key] = 1;
      } else {
        projectionQuery[key] = 0;
      }
    });
  }

  const options = {};
  if (sort) {
    options.sort = sort;
  }

  return User.find(query, projectionQuery, options);
}

// Example usage
